import{_ as r,o as t,c as p,j as e,a as s,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"人生十字路标","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/9.消耗品/0.无支线/人生十字路标 .md","filePath":"4.资源分区/7.物品与装备/9.消耗品/0.无支线/人生十字路标 .md"}'),o={name:"4.资源分区/7.物品与装备/9.消耗品/0.无支线/人生十字路标 .md"};function d(_,a,l,b,i,c){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"人生十字路标",tabindex:"-1"},[s("人生十字路标 "),e("a",{class:"header-anchor",href:"#人生十字路标","aria-label":'Permalink to "人生十字路标"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"汹涌疾风023")])])],-1),n('<h1 id="人生十字路标-1" tabindex="-1">人生十字路标 <a class="header-anchor" href="#人生十字路标-1" aria-label="Permalink to &quot;人生十字路标&quot;">​</a></h1><p>人生十字路标</p><p>无支线奇物/消耗品<br> 1000<br> 由指向不同的银色和黑色箭头组成的交叉路标状项链。因为形状的原因会戳到自己，所以一般被当作挂饰使用。</p><p>当情绪异常进入毁灭状态时，进行一次意志豁免，DC为自身决心值。<br> 若检定成功，消去全部进入毁灭状态的情绪异常点数（即变为距进入毁灭性后果还差1点的状态）。奇物变成【银色涅槃之路标】。<br> 若检定失败，受到3点永久的决心属性伤害。奇物变成【黑色崩毁之路标】。</p><p>“彷徨在人生的十字岔路，崩毁与涅槃只差一步。”</p><p>银色涅槃之路标<br> 项链/护符<br> 由【人生十字路标】的黑色箭头变为银色变化而来。<br> 决心检定+2。<br> 每日一次，你可以将一次决心检定重新掷骰，以新的结果取代原先的结果。</p><p>“只要心不迷惘，条条大路康庄。不论道阻且长，向着旭日起航。”</p><p>黑色崩毁之路标<br> 项链/护符<br> 由【人生十字路标】的银色箭头崩坏，仅剩黑色箭头变化而来。<br> 你无法脱下【黑色崩毁之路标】，你在对抗影响心灵效果的掷骰中-2DP，每日太阳落山后的第一次掷骰双骰取低。<br> 这是一个C级诅咒来源的效果。<br> 注：是否允许以一次无意义掷骰消耗这次双骰取低，以st判断为准。</p><p>“在黑暗之中辗转反侧，伴随深沉的梦魇入眠。自我折磨吧，直到生命终结的那天。”</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
